+    Value *Cond;
+    if (match(Op0, m_Select(m_Value(Cond), m_Value(X), m_FNeg(m_Deferred(X)))) ||
+        match(Op0, m_Select(m_Value(Cond), m_FNeg(m_Value(X)), m_Deferred(X))))
+      return new FCmpInst(Pred, X, Op1, "", &I);
+  }
   // Handle fcmp with instruction LHS and constant RHS.
